@staticmethod
def parse_xml_tool(raw):
    match = re.search(r"<tool(?P<attrs>[^>]*)>(?P<body>.*?)</tool>", raw, re.S)
    if not match:
        return None

def prompt(self, user_message):
    return textwrap.dedent(
        f"""\
        {self.prefix}

        {self.memory_text()}

        Transcript:
        {self.history_text()}

        Current user request:
        {user_message}
        """
    ).strip()

